defmodule WebhookProxyWeb.ProxyController do
  use WebhookProxyWeb, :controller

  @blocked_ip_ranges [
    # Loopback
    {127, 0, 0, 0},
    # Private 10.x.x.x
    {10, 0, 0, 0},
    # Private 172.16.x.x - 172.31.x.x
    {172, 16, 0, 0},
    # Private 192.168.x.x
    {192, 168, 0, 0},
    # Link-local
    {169, 254, 0, 0},
    # Current network
    {0, 0, 0, 0}
