      is_ip_literal?(uri.host) and is_private_ip_string?(uri.host) ->
        {:error, "Access to private/internal IP addresses is not allowed"}

      true ->
        normalized_url = to_string(%URI{uri | fragment: nil})
        {:ok, normalized_url}
    end
