  defp validate_url(_), do: {:error, "URL must be a string"}

  defp resolve_and_validate_host(url) do
    uri = URI.parse(url)
    host = uri.host

    case resolve_host(host) do
      {:ok, ip} ->
        if is_private_ip?(ip) do
          {:error, "Access to private/internal IP addresses is not allowed"}
        else
          {:ok, ip}
        end

      {:error, _reason} ->
        {:error, "Could not resolve hostname: #{host}"}
    end
  end

  defp resolve_host(host) do
    host_charlist = String.to_charlist(host)

    case :inet.getaddr(host_charlist, :inet) do
      {:ok, ip_tuple} -> {:ok, ip_tuple}
      {:error, reason} -> {:error, reason}
    end
  end

  defp is_private_ip?({127, _, _, _}), do: true
  defp is_private_ip?({10, _, _, _}), do: true
  defp is_private_ip?({172, second, _, _}) when second >= 16 and second <= 31, do: true
  defp is_private_ip?({192, 168, _, _}), do: true
  defp is_private_ip?({169, 254, _, _}), do: true
  defp is_private_ip?({0, _, _, _}), do: true
  defp is_private_ip?({255, 255, 255, 255}), do: true
  # Multicast
  defp is_private_ip?({first, _, _, _}) when first >= 224 and first <= 239, do: true
  # Reserved
  defp is_private_ip?({first, _, _, _}) when first >= 240, do: true
  defp is_private_ip?(_), do: false

  defp is_ip_literal?(host) do
    case :inet.parse_address(String.to_charlist(host)) do
      {:ok, _} -> true
